import useAxios from 'axios-hooks';
import '../App.css';
// import { Component } from 'react';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
// import BootstrapTable from 'react-bootstrap-table-next';

function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    for (let element=0; element<JSON.stringify(data['items'].length); element++) {
        return(
                // <div>
                //     <button onClick={refetch}>refetch</button>
                //     <p>{JSON.stringify(data['items'][element]['id'])}</p>
                //     <p>{JSON.stringify(data['items'][element]['name_sing'])}</p>
                // </div>

            <div>
                <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                    <div className="container-fluid py-2">
                        <Link className="navbar-brand fs-3 fw-bold" to="/">roads_admin</Link>
                    </div>
                    <div className="container-fluid bg-dark py-2">
                        <div className="navbar-nav flex-row">
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/" end> Главная </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads" end> Дороги </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/sings" end> Дорожные знаки </NavLink>
                            <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads/sings" end> Знаки на дорогах </NavLink>
                        </div>
                    </div>
                </nav>
                <div className="Sing">
                    <p className="Table-header"><h1>Дороги.</h1></p>

                    <BootstrapTable keyField='id' data={ Sings } columns={ columns } />
                </div>
            </div>
        );
    }
}


